script:
(async function () {
  const host = root_element.querySelector('[data-ta-dashboard-root]');
  if (!host) return;
  const r = await frappe.call({ method: 'upande_ta.upande_ta.api.blocks.render_ta_dashboard' });
  const payload = (r && r.message) || {};
  if (payload.css) {
    const styleEl = document.createElement('style');
    styleEl.textContent = payload.css;
    root_element.appendChild(styleEl);
  }
  host.innerHTML = payload.html || '';
  const js_url = (window.frappe && frappe.assets && frappe.assets.bundled_asset)
    ? frappe.assets.bundled_asset('ta_dashboard.bundle.js')
    : '/assets/upande_ta/js/ta_dashboard.bundle.js';
  await frappe.require(js_url);
  upande_ta.blocks.ta_dashboard.mount(host);
})();
